member.example:
Bind a relay command to a Scrollbar's value change using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ScrollbarCommandBinder _scrollCommand;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Scroll(float value) { }
    }


Bind a relay command in code, receiving the scrollbar value as an int.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Scrollbar _scrollbar;
        
        private ScrollbarCommandBinder ScrollCommand => new(_scrollbar);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Scroll(int value) { }
    }

